const { Client } = require('magicbell-js/project-client');

async function main() {
  const runId = process.env.ZEALT_RUN_ID || 'test1';
  const emailBase = process.env.MAGICBELL_EMAIL || 'test';

  const client = new Client({
    apiKey: process.env.MAGICBELL_API_KEY,
    apiSecret: process.env.MAGICBELL_API_SECRET
  });

  try {
    const response = await client.broadcasts.createBroadcast({
      title: `Topic Broadcast ${runId}`,
      topic: `announcements-${runId}`,
      recipients: [
        { email: `${emailBase}+${runId}@gmail.com` },
        { matches: `topic:announcements-${runId}` }
      ]
    });
    console.log(JSON.stringify(response.data));
  } catch (err) {
    console.error(err.message);
    if (err.response) {
      console.error(err.response.data);
    }
  }
}

main();

