const fs = require('fs');
const { Client } = require('magicbell-js/project-client');
const broadcastModels = require('magicbell-js/dist/commonjs/project-client/services/broadcasts/models/broadcast.js');

// Monkey patch the schema to pass through everything
broadcastModels.broadcastRequest = {
  parse: (data) => data
};

async function main() {
  const runId = process.env.ZEALT_RUN_ID || 'test1';
  const emailBase = process.env.MAGICBELL_EMAIL || 'test';

  const client = new Client({
    token: process.env.MAGICBELL_PROJECT_TOKEN
  });

  try {
    const response = await client.broadcasts.createBroadcast({
      title: `Topic Broadcast ${runId}`,
      topic: `announcements-${runId}`,
      recipients: [
        { email: `${emailBase}+${runId}@gmail.com` },
        { matches: `topic:announcements-${runId}` }
      ]
    });
    const output = JSON.stringify(response.data);
    console.log(output);
    fs.writeFileSync('/home/user/task/output.log', output + '\n');
  } catch (err) {
    console.error(err.message);
    if (err.response) {
      console.error(err.response.data);
    }
  }
}

main();

